  1	import {
  2	  Chart,
  3	  ChartArea,
  4	  ChartAxis,
  5	  ChartBar,
  6	  ChartGroup,
  7	  ChartLabel,
  8	  ChartLegend,
  9	  ChartLine,
 10	  ChartScatter,
 11	  ChartStack,
 12	  ChartThemeColor
 13	} from '@patternfly/react-charts/victory';
 14	import * as React from 'react';
 15	import { useTranslation } from 'react-i18next';
 16	import { GenericMetric, NamedMetric } from '../../api/loki';
 17	import { MetricFunction, MetricType } from '../../model/flow-query';
 18	import { localStorageOverviewMetricsTotalDimensionKey, useLocalStorage } from '../../utils/local-storage-hook';
 19	import { getFormattedValue, isUnknownPeer } from '../../utils/metrics';
 20	import {
 21	  ChartDataPoint,
 22	  defaultDimensions,
 23	  Dimensions,
 24	  LegendDataItem,
 25	  observeDimensions,
 26	  toDatapoints
 27	} from '../../utils/metrics-helper';
 28	import { chartVoronoi } from './chart-voronoi';
 29	import './metrics-content.css';
 30	
 31	export interface MetricsGraphWithTotalProps {
 32	  id: string;
 33	  metricType: MetricType;
 34	  metricFunction: MetricFunction;
 35	  topKMetrics: (GenericMetric | NamedMetric)[];
 36	  totalMetric?: GenericMetric | NamedMetric;
 37	  totalDropMetric?: NamedMetric;
 38	  limit: number;
 39	  showTop: boolean;
 40	  showTotal: boolean;
 41	  showTotalDrop: boolean;
 42	  showOthers: boolean;
 43	  othersName?: string;
 44	  showInternal?: boolean;
 45	  showOutOfScope?: boolean;
 46	  smallerTexts?: boolean;
 47	  topAsBars?: boolean;
 48	  showLegend?: boolean;
 49	  animate?: boolean;
 50	}
 51	
 52	export const MetricsGraphWithTotal: React.FC<MetricsGraphWithTotalProps> = ({
 53	  id,
 54	  metricType,
 55	  metricFunction,
 56	  topKMetrics,
 57	  totalMetric,
 58	  totalDropMetric,
 59	  limit,
 60	  showTop,
 61	  showTotal,
 62	  showTotalDrop,
 63	  showOthers,
 64	  othersName,
 65	  showInternal,
 66	  showOutOfScope,
 67	  smallerTexts,
 68	  topAsBars,
 69	  showLegend,
 70	  animate
 71	}) => {
 72	  const { t } = useTranslation('plugin__netobserv-plugin');
 73	
 74	  let filtered = topKMetrics;
 75	  if (showInternal === false) {
 76	    filtered = (filtered as NamedMetric[]).filter(m => !m.isInternal);
 77	  }
 78	  if (!showOutOfScope === false) {
 79	    filtered = (filtered as NamedMetric[]).filter(m => !isUnknownPeer(m.source) || !isUnknownPeer(m.destination));
 80	  }
 81	  if (showOthers === false && othersName) {
 82	    // remove others from generic metrics (DNS rcode NoError)
 83	    filtered = (filtered as GenericMetric[]).filter(m => showOthers || (othersName && m.name !== othersName));
 84	  }
 85	  filtered = filtered.slice(0, limit);
 86	
 87	  const legendData: LegendDataItem[] = showTop
 88	    ? filtered.map((m, idx) => ({
 89	        childName: `top-${idx}`,
 90	        name: (m as NamedMetric).shortName || (m as GenericMetric).name,
 91	        tooltipName: (m as NamedMetric).fullName || (m as GenericMetric).name
 92	      }))
 93	    : [];
 94	
 95	  if (showTotal && totalMetric) {
 96	    legendData.push({
 97	      childName: 'area-total',
 98	      name: t('Total'),
 99	      symbol: { fill: '#8B8D8F' }
100	    });
101	  }
102	
103	  if (showTotalDrop && totalDropMetric) {
104	    legendData.push({
105	      childName: 'area-totaldrop',
106	      name: t('Total dropped'),
107	      symbol: { fill: '#C9190B' }
108	    });
109	  }
110	
111	  const topKDatapoints: ChartDataPoint[][] = filtered.map(toDatapoints);
112	  const totalDatapoints: ChartDataPoint[] = totalMetric ? toDatapoints(totalMetric) : [];
113	  const totalDropDatapoints: ChartDataPoint[] = totalDropMetric ? toDatapoints(totalDropMetric) : [];
114	
115	  const legentComponent = (
116	    <ChartLegend
117	      itemsPerRow={2}
118	      labelComponent={<ChartLabel className={smallerTexts ? 'small-chart-label' : ''} />}
119	      data={legendData}
120	    />
121	  );
122	
123	  const containerRef = React.useRef<HTMLDivElement>(null);
124	  const [dimensions, setDimensions] = useLocalStorage<Dimensions>(
125	    `${localStorageOverviewMetricsTotalDimensionKey}${showLegend ? '-legend' : ''}`,
126	    defaultDimensions
127	  );
128	
129	  React.useEffect(() => {
130	    return observeDimensions(containerRef, dimensions, setDimensions);
131	  }, [containerRef, dimensions, setDimensions]);
132	
133	  return (
134	    <div id={`chart-${id}`} className="metrics-content-div" ref={containerRef} data-test-metrics={topKMetrics.length}>
135	      <Chart
136	        themeColor={ChartThemeColor.multiUnordered}
137	        containerComponent={
138	          showLegend
139	            ? chartVoronoi(legendData, (v: number) => getFormattedValue(v, metricType, metricFunction, t))
140	            : undefined
141	        }
142	        legendData={legendData}
143	        legendOrientation="horizontal"
144	        legendPosition="bottom-left"
145	        legendAllowWrap={true}
146	        legendComponent={legentComponent}
147	        scale={{ x: 'time', y: 'linear' }}
148	        width={dimensions.width}
149	        height={dimensions.height}
150	        domainPadding={{ x: 0, y: 0 }}
151	        animate={animate}
152	        padding={
153	          showLegend
154	            ? {
155	                bottom: (legendData.length / 2) * 25 + 100,
156	                left: 90,
157	                right: 50,
158	                top: 50
159	              }
160	            : {
161	                bottom: 0,
162	                left: 0,
163	                right: 0,
164	                top: 0
165	              }
166	        }
167	      >
168	        <ChartAxis fixLabelOverlap />
169	        <ChartAxis
170	          dependentAxis
171	          showGrid
172	          fixLabelOverlap
173	          tickFormat={y => (showLegend ? getFormattedValue(y, metricType, metricFunction, t) : '')}
174	        />
175	        {showTop &&
176	          (topAsBars ? (
177	            <ChartStack>
178	              {topKDatapoints.map((datapoints, idx) => (
179	                <ChartBar name={`top-${idx}`} key={`top-${idx}`} data={datapoints} />
180	              ))}
181	            </ChartStack>
182	          ) : (
183	            <ChartGroup>
184	              {topKDatapoints.map((datapoints, idx) => (
185	                <ChartLine name={`top-${idx}`} key={`top-${idx}`} data={datapoints} interpolation="monotoneX" />
186	              ))}
187	            </ChartGroup>
188	          ))}
189	        {showTotal && (
190	          <ChartGroup>
191	            <ChartArea
192	              name={'area-total'}
193	              style={{ data: { fill: '#8B8D8F' } }}
194	              data={totalDatapoints}
195	              interpolation="monotoneX"
196	            />
197	          </ChartGroup>
198	        )}
199	        {showTotal && (
200	          <ChartGroup>
201	            <ChartScatter name={'scatter-total'} style={{ data: { fill: '#8B8D8F' } }} data={totalDatapoints} />
202	          </ChartGroup>
203	        )}
204	        {showTotalDrop && (
205	          <ChartGroup>
206	            <ChartArea
207	              name={'area-totaldrop'}
208	              style={{ data: { fill: '#C9190B' } }}
209	              data={totalDropDatapoints}
210	              interpolation="monotoneX"
211	            />
212	          </ChartGroup>
213	        )}
214	        {showTotalDrop && (
215	          <ChartGroup>
216	            <ChartScatter name={'scatter-totaldrop'} style={{ data: { fill: '#C9190B' } }} data={totalDropDatapoints} />
217	          </ChartGroup>
218	        )}
219	      </Chart>
220	    </div>
221	  );
222	};

